Get-ScheduledTask | Where-Object State -eq 'Ready' | Select-Object -First 3 | ForEach-Object {
    $info = Get-ScheduledTaskInfo -TaskName $_.TaskName -TaskPath $_.TaskPath -ErrorAction SilentlyContinue
    [PSCustomObject]@{
        Nom         = $_.TaskName
        DernierRun  = $info.LastRunTime
        ProchainRun = $info.NextRunTime
    }
} | Format-Table -AutoSize
